import React, { useEffect, useState } from 'react';
import Layout from '../../components/shared/Layout';
import axiosInstance from '../../utils/axiosInstance';

const StatCard = ({ label, value, color }) => (
  <div style={{ background: '#fff', borderRadius: 12, padding: '20px 24px', boxShadow: '0 2px 8px rgba(0,0,0,0.06)', borderLeft: `4px solid ${color}`, height: '100%' }}>
    <p style={{ margin: '0 0 6px', color: '#64748b', fontSize: 13 }}>{label}</p>
    <h3 style={{ margin: 0, fontSize: 26, color: '#1e293b' }}>{value ?? '—'}</h3>
  </div>
);

export default function AdminDashboard() {
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    axiosInstance.get('/admin/stats').then(r => { setStats(r.data.stats); setLoading(false); }).catch(() => setLoading(false));
  }, []);

  if (loading) return <Layout><p>Loading stats...</p></Layout>;
  if (!stats) return <Layout><p style={{ color: '#ef4444' }}>Failed to load stats</p></Layout>;

  const sections = [
    {
      title: ' Customers', color: '#3b82f6', cards: [
        ['Total Customers', stats.customers.total],
        ['Active', stats.customers.active],
        ['Pending KYC', stats.customers.pendingKYC],
        ['AT RISK Accounts', stats.customers.atRisk],
      ]
    },
    {
      title: ' Accounts', color: '#8b5cf6', cards: [
        ['Total Accounts', stats.accounts.total],
        ['Pending Approval', stats.accounts.pending],
        ['Total Balance Held', `₹${stats.accounts.totalBalance?.toLocaleString('en-IN')}`],
      ]
    },
    {
      title: ' Transactions (Today)', color: '#22c55e', cards: [
        ['Total Transactions', stats.transactions.total],
        ["Today's Count", stats.transactions.todayCount],
        ['Deposited Today', `₹${stats.transactions.todayDeposited?.toLocaleString('en-IN')}`],
        ['Withdrawn Today', `₹${stats.transactions.todayWithdrawn?.toLocaleString('en-IN')}`],
      ]
    },
    {
      title: ' Loans', color: '#f59e0b', cards: [
        ['Pending Approvals', stats.loans.pending],
        ['Active Loans', stats.loans.active],
        ['Total Disbursed', `₹${stats.loans.totalDisbursed?.toLocaleString('en-IN')}`],
      ]
    },
    {
      title: ' Investments', color: '#ec4899', cards: [
        ['Active FDs', stats.investments.activeFDs],
        ['Active RDs', stats.investments.activeRDs],
      ]
    },
    {
      title: ' Support', color: '#64748b', cards: [
        ['Open Tickets', stats.support.open],
        ['In Progress', stats.support.inProgress],
      ]
    },
  ];

  return (
    <Layout>
      <div className="pt-5 pt-md-0">
        <h2 style={{ margin: '0 0 28px', color: '#1e293b' }}> Admin Dashboard</h2>
      </div>
      {sections.map(sec => (
        <div key={sec.title} style={{ marginBottom: 32 }}>
          <h3 style={{ margin: '0 0 16px', color: '#475569', fontSize: 16 }}>{sec.title}</h3>
          <div className="row g-3">
            {sec.cards.map(([lbl, val]) => (
              <div key={lbl} className="col-12 col-sm-6 col-lg-4 col-xl-3">
                <StatCard label={lbl} value={val} color={sec.color} />
              </div>
            ))}
          </div>
        </div>
      ))}
    </Layout>
  );
}
